import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PageView {
  DASHBOARD = 'DASHBOARD',
  DISCOVERY = 'DISCOVERY',
  PROPOSAL = 'PROPOSAL',
  DEAL_HEALTH = 'DEAL_HEALTH',
  SETTINGS = 'SETTINGS'
}

export interface NavItem {
  id: PageView;
  label: string;
  icon: React.ReactNode;
}

export interface MetricCardProps {
  title: string;
  value: string;
  trend?: string;
  trendUp?: boolean;
  icon: React.ReactNode;
}

import React, { useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './pages/Dashboard';
import { DiscoveryCopilot } from './pages/DiscoveryCopilot';
import { ProposalReview } from './pages/ProposalReview';
import { DealHealthChecker } from './pages/DealHealthChecker';
import { PageView } from './types';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>(PageView.DASHBOARD);

  const renderContent = () => {
    switch (activePage) {
      case PageView.DASHBOARD:
        return <Dashboard />;
      case PageView.DISCOVERY:
        return <DiscoveryCopilot />;
      case PageView.PROPOSAL:
        return <ProposalReview />;
      case PageView.DEAL_HEALTH:
        return <DealHealthChecker />;
      case PageView.SETTINGS:
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
            <h2 className="text-xl font-semibold mb-2">Settings</h2>
            <p>User preferences and API configurations would go here.</p>
          </div>
        );
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
      <Sidebar activePage={activePage} onNavigate={setActivePage} />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header activePage={activePage} />

        <main className="flex-1 overflow-y-auto p-6 scroll-smooth">
          <div className="max-w-6xl mx-auto w-full">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

