    decisionMakerIdentified: 'Yes',
    daysSinceInteraction: '',
    proposalSent: 'Yes',
    objections: '',
    urgency: 'Medium',
    competitors: 'Yes'
  });

  const [result, setResult] = useState<any>(null);

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const calculateHealth = () => {
    // Simple mock logic for demo
    const isObjections = formData.objections.length > 5;
    const isOldInteraction = parseInt(formData.daysSinceInteraction || '0') > 7;

    let status = 'Strong';
    let probability = 75;
    let reasoning = 'Regular communication and identified decision maker suggests positive momentum.';

    if (isObjections && isOldInteraction) {
