    name: '',
    contactPerson: '',
    email: '',
    status: 'Active'
  });

  const handleAddCompany = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCompany.name || !newCompany.contactPerson || !newCompany.email) return;

