                      <p className="text-sm text-slate-400">Based on industry standards for {clientType}</p>
                   </div>
                   <ScoreGauge score={result.score} max={10} />
                </Card>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                   <Card className="border-t-4 border-t-rose-500">
                      <h4 className="font-semibold text-slate-200 mb-4 flex items-center gap-2">
                        <XCircle size={18} className="text-rose-500" /> Weak Areas
                      </h4>
                      <ul className="space-y-3">
                        {result.weakAreas.map((item: string, i: number) => (
                           <li key={i} className="text-sm text-slate-400 leading-snug pl-4 border-l-2 border-slate-800">
                              {item}
                           </li>
                        ))}
                      </ul>
                   </Card>

                   <Card className="border-t-4 border-t-amber-500">
                      <h4 className="font-semibold text-slate-200 mb-4 flex items-center gap-2">
                        <Zap size={18} className="text-amber-500" /> What is Missing
                      </h4>
                      <ul className="space-y-3">
                        {result.missingInfo.map((item: string, i: number) => (
                           <li key={i} className="text-sm text-slate-400 leading-snug pl-4 border-l-2 border-slate-800">
                              {item}
                           </li>
                        ))}
                      </ul>
                   </Card>
                </div>

                <Card className="border-indigo-500/30 bg-indigo-900/10">
                   <CardHeader title="Recommended Rewrite" description="Try this phrasing for better impact:" />
                   <div className="bg-slate-900/80 rounded-lg p-4 border border-indigo-500/20 relative">
                      <div className="absolute top-0 right-0 p-2 opacity-20">
                         <Zap size={40} />
                      </div>
                      <p className="text-indigo-200 italic text-sm leading-relaxed">
                         "{result.improvedSnippet}"
                      </p>
                      <button 
                        onClick={() => showToast("Copied to clipboard", "info")}
                        className="mt-4 text-xs font-semibold text-indigo-400 hover:text-indigo-300 flex items-center gap-1 uppercase tracking-wider"
                      >
                         <Check size={14} /> Copy to clipboard
                      </button>
                   </div>
                </Card>
             </div>
          ) : (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-50">
                <FileText size={64} strokeWidth={1} className="mb-4" />
                <p>Waiting for proposal text...</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Card } from '../components/Card';
import { Tooltip } from '../components/Tooltip';
import { Activity, ShieldAlert, ArrowRight } from 'lucide-react';
import { useToast } from '../context/ToastContext';

export const DealHealthChecker: React.FC = () => {
  const { showToast } = useToast();
  const [formData, setFormData] = useState({
    propertyType: 'Residential',
    decisionMakerIdentified: 'Yes',
    daysSinceInteraction: '',
    proposalSent: 'Yes',
    objections: '',
    urgency: 'Medium',
    competitors: 'Yes'
  });

  const [result, setResult] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const calculateHealth = () => {
    setIsAnalyzing(true);
    setResult(null);

    setTimeout(() => {
      const isObjections = formData.objections.length > 5;
      const days = parseInt(formData.daysSinceInteraction || '0');
      const isOldInteraction = days > 7;

      let status = 'Strong';
      let probability = 75;
      let reasoning = 'Regular communication and identified decision maker suggests positive momentum.';
      let nextActions = [
        'Send a case study relevant to their specific property type.',
        'Propose a site walkthrough if not already completed.'
      ];

      // Logic per requirements
      if (formData.decisionMakerIdentified === 'No' && isOldInteraction) {
        status = 'Likely Lost';
        probability = 20;
        reasoning = 'No decision maker identified combined with silence for > 7 days indicates the deal has stalled significantly.';
        nextActions = [
           'Attempt a "break-up" email to trigger a response.',
           'Call the main office line to identify the correct stakeholder.'
        ];
      } else if (isObjections && formData.competitors === 'Yes') {
        status = 'At Risk';
        probability = 45;
        reasoning = 'Active objections while competitors are involved puts this deal at significant risk of churn.';
        nextActions = [
           'Schedule a "barrier removal" call specifically to address the objection.',
           'Offer a limited-time incentive for signing this week to combat competitors.'
        ];
      }

      setResult({
        status,
        probability,
        reasoning,
        nextActions
      });
      setIsAnalyzing(false);
      showToast("Deal health evaluated");
    }, 800);
  };

  return (
    <div className="space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
            <Activity className="text-rose-500" /> Deal Health Checker
          </h1>
          <p className="text-slate-400 mt-1">Evaluate deal risk and get clear next actions.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Form Section */}
          <div className="lg:col-span-7">
            <Card>
              <h3 className="text-lg font-semibold text-slate-100 mb-6 border-b border-slate-800 pb-4">Deal Parameters</h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div>
                    <label className="label-text">
                      Property Type
                      <Tooltip text="The primary category of the facility requiring security services." />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.propertyType}
                      onChange={(e) => handleChange('propertyType', e.target.value)}
                    >
                       <option>Residential</option>
                       <option>Commercial</option>
                       <option>Industrial</option>
                       <option>Retail</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Decision Maker Identified?
                      <Tooltip text="Have you confirmed exactly who has the final authority to sign the contract?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.decisionMakerIdentified}
                      onChange={(e) => handleChange('decisionMakerIdentified', e.target.value)}
                    >
                       <option>Yes</option>
                       <option>No</option>
                       <option>Unsure</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Last Interaction (Days ago)
                      <Tooltip text="Number of days since the last two-way communication (email, call, or meeting)." />
                    </label>
                    <input 
                      type="number" 
                      className="input-field"
                      placeholder="e.g. 3"
                      value={formData.daysSinceInteraction}
                      onChange={(e) => handleChange('daysSinceInteraction', e.target.value)}
                    />
                 </div>

                 <div>
                    <label className="label-text">
                      Proposal Sent?
                      <Tooltip text="Has the formal pricing and scope of work document been delivered?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.proposalSent}
                      onChange={(e) => handleChange('proposalSent', e.target.value)}
                    >
                       <option>Yes</option>
                       <option>No</option>
                       <option>Drafting</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Client Urgency
                      <Tooltip text="How quickly does the client need to deploy services on-site?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.urgency}
                      onChange={(e) => handleChange('urgency', e.target.value)}
                    >
                       <option>High</option>
                       <option>Medium</option>
                       <option>Low</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Competitors Involved?
                      <Tooltip text="Are other security guard companies actively bidding on this contract?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.competitors}
                      onChange={(e) => handleChange('competitors', e.target.value)}
                    >
                       <option>Yes</option>
                       <option>No</option>
                       <option>Unknown</option>
                    </select>
                 </div>

                 <div className="md:col-span-2">
                    <label className="label-text">
                      Objections Raised (Optional)
                      <Tooltip text="Any specific concerns mentioned by the client (e.g., price, reputation, timing)." />
                    </label>
                    <input 
                      type="text" 
                      className="input-field"
                      placeholder="e.g. Price too high, current contract not expired..."
                      value={formData.objections}
                      onChange={(e) => handleChange('objections', e.target.value)}
                    />
                 </div>
              </div>

              <div className="mt-8 pt-6 border-t border-slate-800">
                <button 
                  onClick={calculateHealth}
                  disabled={isAnalyzing}
                  className="w-full bg-slate-100 hover:bg-white text-slate-900 font-bold py-3 rounded-lg shadow-lg shadow-white/10 transition-colors disabled:opacity-70 disabled:cursor-not-allowed"
                >
                  {isAnalyzing ? 'Evaluating Deal...' : 'Evaluate Deal Health'}
                </button>
              </div>
            </Card>
          </div>

          {/* Results Section */}
          <div className="lg:col-span-5">
             {result ? (
               <div className="space-y-4 animate-fade-in h-full">
                  <div className={`rounded-xl p-8 text-center border transition-all duration-500 ${
                    result.status === 'Strong' ? 'bg-emerald-500/10 border-emerald-500/30' : 
                    result.status === 'At Risk' ? 'bg-amber-500/10 border-amber-500/30' : 
                    'bg-rose-500/10 border-rose-500/30'
                  }`}>
                     <h2 className={`text-3xl font-bold mb-2 ${
                       result.status === 'Strong' ? 'text-emerald-400' : 
                       result.status === 'At Risk' ? 'text-amber-400' : 
                       'text-rose-400'
                     }`}>{result.status}</h2>
                     <p className="text-slate-400 text-sm uppercase tracking-widest font-semibold">Deal Status</p>

                     <div className="mt-6 flex items-center justify-center gap-2">
                       <span className="text-5xl font-bold text-slate-100">{result.probability}%</span>
                     </div>
                     <p className="text-slate-500 text-sm mt-1">Close Probability</p>
                  </div>

                  <Card className="border-l-4 border-l-blue-500">
                     <h4 className="font-semibold text-slate-200 mb-3">AI Reasoning</h4>
                     <p className="text-sm text-slate-400 leading-relaxed">
                        {result.reasoning}
                     </p>
                  </Card>

                  <Card>
                     <h4 className="font-semibold text-slate-200 mb-4 flex items-center gap-2">
                        <ArrowRight size={16} className="text-blue-500" /> Recommended Actions
                     </h4>
                     <ul className="space-y-3">
                        {result.nextActions.map((action: string, i: number) => (
                           <li key={i} className="flex items-start gap-3 text-sm text-slate-300">
                              <div className="mt-1 w-4 h-4 rounded-full border border-slate-600 flex items-center justify-center shrink-0">
                                 <div className="w-2 h-2 rounded-full bg-slate-600"></div>
                              </div>
                              {action}
                           </li>
                        ))}
                     </ul>
                  </Card>
               </div>
             ) : (
                <div className="h-full bg-slate-900 border border-slate-800 rounded-xl flex flex-col items-center justify-center text-slate-500 p-8 text-center">
                   <ShieldAlert size={48} className="mb-4 text-slate-700" />
                   <h3 className="text-lg font-medium text-slate-400">Awaiting Input</h3>
                   <p className="max-w-xs mt-2 text-sm">Fill out the deal parameters on the left to generate a risk assessment.</p>
                </div>
             )}
          </div>

        </div>

        <style>{`
          .label-text {
            display: flex;
            align-items: center;
            font-size: 0.75rem;
            font-weight: 500;
            color: #94a3b8;
            margin-bottom: 0.5rem;
            text-transform: uppercase;
          }
          .input-field {
            width: 100%;
            background-color: #1e293b;
            border: 1px solid #334155;
            border-radius: 0.5rem;
            padding: 0.625rem 0.875rem;
            color: #e2e8f0;
            font-size: 0.875rem;
          }
          .input-field:focus {
            outline: none;
            border-color: #3b82f6;
            box-shadow: 0 0 0 1px #3b82f6;
          }
        `}</style>
    </div>
  );
};

import React, { useState } from 'react';
import { Card } from '../components/Card';
import { Modal } from '../components/Modal';
import { Plus, Building2, Search, Mail, User, MoreHorizontal, Edit2, Trash2, AlertTriangle } from 'lucide-react';
import { Company } from '../types';
import { useToast } from '../context/ToastContext';

export const Companies: React.FC = () => {
  const { showToast } = useToast();

  // -- State --
  const [companies, setCompanies] = useState<Company[]>([
    { id: 1, name: "Guardian Mall Services", contactPerson: "Sarah Connor", email: "sarah@guardian.com", status: "Active" },
    { id: 2, name: "Tech Park Security", contactPerson: "John Doe", email: "john@techpark.com", status: "Trial" },
    { id: 3, name: "Westside Logistics", contactPerson: "Mike Ross", email: "m.ross@westside.com", status: "Active" },
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

  // Form State
  const [isEditing, setIsEditing] = useState(false);
  const [currentId, setCurrentId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    contactPerson: '',
    email: '',
    status: 'Active'
  });

  // -- Handlers --

  const resetForm = () => {
    setFormData({ name: '', contactPerson: '', email: '', status: 'Active' });
    setIsEditing(false);
    setCurrentId(null);
  };

  const openAddModal = () => {
    resetForm();
    setIsModalOpen(true);
  };

  const openEditModal = (company: Company) => {
    setFormData({
      name: company.name,
      contactPerson: company.contactPerson,
      email: company.email,
      status: company.status
    });
    setCurrentId(company.id);
    setIsEditing(true);
    setIsModalOpen(true);
  };

  const openDeleteModal = (id: number) => {
    setCurrentId(id);
    setIsDeleteModalOpen(true);
  };

  const validateForm = () => {
    if (!formData.name.trim()) return "Company Name is required";
    if (!formData.contactPerson.trim()) return "Contact Person is required";
    if (!formData.email.trim() || !/^\S+@\S+\.\S+$/.test(formData.email)) return "Valid Email is required";
    return null;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const error = validateForm();
    if (error) {
      showToast(error, 'error');
      return;
    }

    if (isEditing && currentId) {
      // Update existing
      setCompanies(prev => prev.map(c => c.id === currentId ? { ...c, ...formData, status: formData.status as 'Active' | 'Trial' } : c));
      showToast("Company updated successfully", "success");
    } else {
      // Add new
      const newCompany: Company = {
        id: Date.now(),
        name: formData.name,
        contactPerson: formData.contactPerson,
        email: formData.email,
        status: formData.status as 'Active' | 'Trial'
      };
      setCompanies(prev => [newCompany, ...prev]);
      showToast("Company added successfully", "success");
    }
    setIsModalOpen(false);
    resetForm();
  };

  const handleDelete = () => {
    if (currentId) {
      setCompanies(prev => prev.filter(c => c.id !== currentId));
      showToast("Company deleted", "info");
      setIsDeleteModalOpen(false);
      setCurrentId(null);
    }
  };

  // -- Render Helpers --

  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.contactPerson.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
            <Building2 className="text-blue-500" /> Companies
          </h1>
          <p className="text-slate-400 mt-1">Manage your client list and track status.</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors shadow-lg shadow-blue-500/20"
        >
          <Plus size={18} />
          Add New Company
        </button>
      </div>

      {/* Main Content */}
      <Card noPadding className="overflow-hidden min-h-[400px] flex flex-col">
        {/* Search Bar */}
        <div className="p-4 border-b border-slate-800 bg-slate-900/50 flex items-center gap-3">
          <Search size={16} className="text-slate-500" />
          <input 
            type="text" 
            placeholder="Search by company or contact..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="bg-transparent border-none focus:outline-none text-sm text-slate-200 placeholder-slate-500 w-full"
          />
        </div>

        {/* Table or Empty State */}
        {companies.length === 0 ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-500 p-12">
            <div className="w-16 h-16 bg-slate-800/50 rounded-full flex items-center justify-center mb-4">
               <Building2 size={32} className="text-slate-600" />
            </div>
            <h3 className="text-lg font-medium text-slate-300">No companies added yet</h3>
            <p className="max-w-xs mt-2 text-sm text-center mb-6">Start building your client database to track proposals and deal health.</p>
            <button 
              onClick={openAddModal}
              className="text-blue-400 hover:text-blue-300 font-medium text-sm"
            >
              Add your first company &rarr;
            </button>
          </div>
        ) : filteredCompanies.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="border-b border-slate-800 bg-slate-900/50 text-xs font-semibold text-slate-500 uppercase tracking-wider">
                  <th className="px-6 py-4">Company Name</th>
                  <th className="px-6 py-4">Contact Person</th>
                  <th className="px-6 py-4">Email</th>
                  <th className="px-6 py-4">Status</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-800">
                {filteredCompanies.map((company) => (
                  <tr key={company.id} className="group hover:bg-slate-800/30 transition-colors">
                    <td className="px-6 py-4 text-slate-200 font-medium">
                      {company.name}
                    </td>
                    <td className="px-6 py-4 text-slate-400">
                      <div className="flex items-center gap-2">
                        <User size={14} className="text-slate-600" /> {company.contactPerson}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-400">
                      <div className="flex items-center gap-2">
                        <Mail size={14} className="text-slate-600" /> {company.email}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-medium border ${
                        company.status === 'Active' 
                          ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' 
                          : 'bg-amber-500/10 text-amber-400 border-amber-500/20'
                      }`}>
                        {company.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => openEditModal(company)}
                          className="p-2 hover:bg-slate-700 rounded-md text-slate-400 hover:text-blue-400 transition-colors"
                          title="Edit"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => openDeleteModal(company.id)}
                          className="p-2 hover:bg-slate-700 rounded-md text-slate-400 hover:text-rose-400 transition-colors"
                          title="Delete"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
           <div className="p-12 text-center text-slate-500">
             <Search size={32} className="mx-auto mb-4 opacity-20" />
             <p>No companies found matching "{searchTerm}"</p>
           </div>
        )}
      </Card>

      {/* Add/Edit Modal */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={isEditing ? "Edit Company" : "Add New Company"}
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase">Company Name</label>
            <input 
              type="text"
              value={formData.name}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500 placeholder-slate-600"
              placeholder="e.g. Acme Security"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase">Contact Person</label>
            <input 
              type="text"
              value={formData.contactPerson}
              onChange={(e) => setFormData({...formData, contactPerson: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500 placeholder-slate-600"
              placeholder="e.g. John Doe"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase">Email Address</label>
            <input 
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500 placeholder-slate-600"
              placeholder="john@example.com"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase">Status</label>
            <select
              value={formData.status}
              onChange={(e) => setFormData({...formData, status: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500"
            >
              <option value="Active">Active</option>
              <option value="Trial">Trial</option>
            </select>
          </div>
          <div className="pt-4 flex gap-3">
             <button 
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 py-2.5 rounded-lg font-medium transition-colors"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex-1 bg-blue-600 hover:bg-blue-500 text-white py-2.5 rounded-lg font-medium transition-colors"
            >
              {isEditing ? "Save Changes" : "Create Company"}
            </button>
          </div>
        </form>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        title="Delete Company"
      >
        <div className="text-center">
          <div className="w-12 h-12 bg-rose-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
             <AlertTriangle className="text-rose-500" size={24} />
          </div>
          <p className="text-slate-300 mb-6">
            Are you sure you want to delete this company? This action cannot be undone and will remove all associated data.
          </p>
          <div className="flex gap-3">
             <button 
              onClick={() => setIsDeleteModalOpen(false)}
              className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 py-2.5 rounded-lg font-medium transition-colors"
            >
              Cancel
            </button>
            <button 
              onClick={handleDelete}
              className="flex-1 bg-rose-600 hover:bg-rose-500 text-white py-2.5 rounded-lg font-medium transition-colors"
            >
              Delete Company
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState } from 'react';
import { Card } from '../components/Card';
import { Tooltip } from '../components/Tooltip';
import { Activity, ShieldAlert, ArrowRight, Zap } from 'lucide-react';
import { useToast } from '../context/ToastContext';

export const DealHealthChecker: React.FC = () => {
  const { showToast } = useToast();
  const [formData, setFormData] = useState({
    propertyType: 'Residential',
    decisionMakerIdentified: 'Yes',
    daysSinceInteraction: '',
    proposalSent: 'Yes',
    objections: '',
    urgency: 'Medium',
    competitors: 'Yes'
  });

  const [result, setResult] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    // Reset result if user changes input to encourage re-evaluation
    if (result) setResult(null); 
  };

  const calculateHealth = () => {
    setIsAnalyzing(true);
    setResult(null);

    // Realistic delay for analysis feeling
    setTimeout(() => {
      const objectionsExist = formData.objections.trim().length > 0;
      const days = parseInt(formData.daysSinceInteraction || '0');

      let status = 'Strong';
      let probability = 75;
      let reasoning = '';
      let nextActions = [];

      // LOGIC IMPLEMENTATION

      // 1. Likely Lost Condition: No DM and Ghosted > 7 Days
      if (formData.decisionMakerIdentified === 'No' && days > 7) {
        status = 'Likely Lost';
        probability = 15;
        reasoning = 'Critically low engagement. Lacking a decision maker combined with over a week of silence indicates the prospect has likely moved on or deprioritized this.';
        nextActions = [
           'Send a "break-up" email (e.g., "Should I close this file?") to trigger a response.',
           'Call the main office line to identify the correct stakeholder.',
           'Do not invest more time in proposal customization until contact is re-established.'
        ];
      } 
      // 2. At Risk Condition: Objections AND Competitors
      else if (objectionsExist && formData.competitors === 'Yes') {
        status = 'At Risk';
        probability = 40;
        reasoning = `The deal is precarious. The client has voiced concerns ("${formData.objections.substring(0, 30)}...") and is actively shopping competitors. They are looking for a reason to say no.`;
        nextActions = [
           'Schedule a "barrier removal" call specifically to address the objection.',
           'Prepare a competitor comparison sheet highlighting your unique strengths.',
           'Offer a limited-time incentive for signing this week.'
        ];
      }
      // 3. Strong Condition: High Urgency + DM Identified
      else if (formData.urgency === 'High' && formData.decisionMakerIdentified === 'Yes') {
        status = 'Strong';
        probability = 85;
        reasoning = 'Excellent momentum. High urgency from the client combined with direct access to the decision maker is the perfect recipe for a close.';
        nextActions = [
           'Send the contract immediately via Docusign.',
           'Propose a tentative start date to assume the sale.',
           'Ask: "Is there anything preventing you from signing today?"'
        ];
      }
      // 4. Moderate/Default
      else {
        status = 'Moderate';
        probability = 60;
        reasoning = 'The deal is stable but lacks urgency. You have some engagement, but no clear buying signal has been triggered yet.';
        nextActions = [
           'Send a relevant case study for a ' + formData.propertyType + ' property.',
           'Propose a site walkthrough if not already completed.',
           'Check in via text message for a quicker response.'
        ];
      }

      setResult({
        status,
        probability,
        reasoning,
        nextActions
      });
      setIsAnalyzing(false);
      showToast("Deal analysis complete", "success");
    }, 800);
  };

  return (
    <div className="space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
            <Activity className="text-rose-500" /> Deal Health Checker
          </h1>
          <p className="text-slate-400 mt-1">Evaluate deal risk and get clear next actions.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Form Section */}
          <div className="lg:col-span-7">
            <Card>
              <div className="flex items-center justify-between mb-6 border-b border-slate-800 pb-4">
                 <h3 className="text-lg font-semibold text-slate-100">Deal Parameters</h3>
                 <button 
                    onClick={() => setFormData({
                        propertyType: 'Residential',
                        decisionMakerIdentified: 'Yes',
                        daysSinceInteraction: '2',
                        proposalSent: 'Yes',
                        objections: '',
                        urgency: 'Medium',
                        competitors: 'No'
                    })}
                    className="text-xs text-blue-400 hover:text-blue-300"
                 >
                    Reset Form
                 </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div>
                    <label className="label-text">
                      Property Type
                      <Tooltip text="The primary category of the facility requiring security services." />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.propertyType}
                      onChange={(e) => handleChange('propertyType', e.target.value)}
                    >
                       <option>Residential</option>
                       <option>Commercial</option>
                       <option>Industrial</option>
                       <option>Retail</option>
                       <option>Event</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Decision Maker Identified?
                      <Tooltip text="Have you confirmed exactly who has the final authority to sign the contract?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.decisionMakerIdentified}
                      onChange={(e) => handleChange('decisionMakerIdentified', e.target.value)}
                    >
                       <option>Yes</option>
                       <option>No</option>
                       <option>Unsure</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Last Interaction (Days ago)
                      <Tooltip text="Number of days since the last two-way communication (email, call, or meeting)." />
                    </label>
                    <input 
                      type="number" 
                      min="0"
                      className="input-field"
                      placeholder="e.g. 3"
                      value={formData.daysSinceInteraction}
                      onChange={(e) => handleChange('daysSinceInteraction', e.target.value)}
                    />
                 </div>

                 <div>
                    <label className="label-text">
                      Proposal Sent?
                      <Tooltip text="Has the formal pricing and scope of work document been delivered?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.proposalSent}
                      onChange={(e) => handleChange('proposalSent', e.target.value)}
                    >
                       <option>Yes</option>
                       <option>No</option>
                       <option>Drafting</option>
                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Client Urgency
                      <Tooltip text="How quickly does the client need to deploy services on-site?" />
                    </label>
                    <select 
