                    </select>
                 </div>

                 <div>
                    <label className="label-text">
                      Competitors Involved?
                      <Tooltip text="Are other security guard companies actively bidding on this contract?" />
                    </label>
                    <select 
                      className="input-field"
                      value={formData.competitors}
                      onChange={(e) => handleChange('competitors', e.target.value)}
                    >
                       <option>Yes</option>
                       <option>No</option>
                       <option>Unknown</option>
                    </select>
                 </div>

                 <div className="md:col-span-2">
                    <label className="label-text">
                      Objections Raised (Optional)
                      <Tooltip text="Any specific concerns mentioned by the client (e.g., price, reputation, timing)." />
                    </label>
                    <input 
                      type="text" 
                      className="input-field"
                      placeholder="e.g. Price too high, current contract not expired..."
                      value={formData.objections}
                      onChange={(e) => handleChange('objections', e.target.value)}
                    />
                 </div>
              </div>

              <div className="mt-8 pt-6 border-t border-slate-800">
                <button 
                  onClick={calculateHealth}
                  disabled={isAnalyzing}
                  className="w-full bg-slate-100 hover:bg-white text-slate-900 font-bold py-3 rounded-lg shadow-lg shadow-white/10 transition-colors disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                  {isAnalyzing ? (
                     <>
                        <div className="w-5 h-5 border-2 border-slate-900/30 border-t-slate-900 rounded-full animate-spin"></div>
                        Evaluating...
                     </>
                  ) : (
                     <>
                        <Zap size={18} />
                        Evaluate Deal Health
                     </>
                  )}
                </button>
              </div>
            </Card>
          </div>

          {/* Results Section */}
          <div className="lg:col-span-5">
             {result ? (
               <div className="space-y-4 animate-fade-in h-full">
                  <div className={`rounded-xl p-8 text-center border transition-all duration-500 ${
                    result.status === 'Strong' ? 'bg-emerald-500/10 border-emerald-500/30 shadow-[0_0_30px_-5px_rgba(16,185,129,0.2)]' : 
                    result.status === 'Moderate' ? 'bg-blue-500/10 border-blue-500/30' :
                    result.status === 'At Risk' ? 'bg-amber-500/10 border-amber-500/30 shadow-[0_0_30px_-5px_rgba(245,158,11,0.2)]' : 
                    'bg-rose-500/10 border-rose-500/30 shadow-[0_0_30px_-5px_rgba(244,63,94,0.2)]'
                  }`}>
                     <h2 className={`text-4xl font-extrabold mb-2 tracking-tight ${
                       result.status === 'Strong' ? 'text-emerald-400' : 
                       result.status === 'Moderate' ? 'text-blue-400' :
                       result.status === 'At Risk' ? 'text-amber-400' : 
                       'text-rose-400'
