                </>
              )}
            </button>
          </Card>
        </div>

        {/* Output Section */}
        <div className="h-full">
          {result ? (
            <div className="space-y-6 animate-fade-in h-full">
              <Card className="border-l-4 border-l-blue-500 h-full">
                <CardHeader 
                  title="Analysis Result" 
                  action={<ScoreGauge score={result.score} label="Quality Score" />}
