import React, { useState } from 'react';
import { Card } from '../components/Card';
import { Modal } from '../components/Modal';
import { Plus, Building2, Search, Mail, User, Edit2, Trash2, AlertTriangle } from 'lucide-react';
import { Company } from '../types';
import { useToast } from '../context/ToastContext';

export const Companies: React.FC = () => {
  const { showToast } = useToast();

  // -- State --
  const [companies, setCompanies] = useState<Company[]>([
    { id: 1, name: "Guardian Mall Services", contactPerson: "Sarah Connor", email: "sarah@guardian.com", status: "Active" },
    { id: 2, name: "Tech Park Security", contactPerson: "John Doe", email: "john@techpark.com", status: "Trial" },
    { id: 3, name: "Westside Logistics", contactPerson: "Mike Ross", email: "m.ross@westside.com", status: "Active" },
    { id: 4, name: "City Center Lofts", contactPerson: "Jane Smith", email: "jane@citycenter.com", status: "Active" },
    { id: 5, name: "Harbor Event Space", contactPerson: "Bill Turner", email: "bill@harbor.com", status: "Trial" },
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

  // Form State
  const [isEditing, setIsEditing] = useState(false);
  const [currentId, setCurrentId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    contactPerson: '',
    email: '',
    status: 'Active'
  });

  // -- Handlers --

  const resetForm = () => {
    setFormData({ name: '', contactPerson: '', email: '', status: 'Active' });
    setIsEditing(false);
    setCurrentId(null);
  };

  const openAddModal = () => {
    resetForm();
    setIsModalOpen(true);
  };

  const openEditModal = (company: Company) => {
    setFormData({
      name: company.name,
      contactPerson: company.contactPerson,
      email: company.email,
      status: company.status
    });
    setCurrentId(company.id);
    setIsEditing(true);
    setIsModalOpen(true);
  };

  const openDeleteModal = (id: number) => {
    setCurrentId(id);
    setIsDeleteModalOpen(true);
  };

  const validateForm = () => {
    if (!formData.name.trim()) return "Company Name is required";
    if (!formData.contactPerson.trim()) return "Contact Person is required";
    if (!formData.email.trim() || !/^\S+@\S+\.\S+$/.test(formData.email)) return "Valid Email is required";
    return null;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const error = validateForm();
    if (error) {
      showToast(error, 'error');
      return;
    }

    if (isEditing && currentId) {
      // Update existing
      setCompanies(prev => prev.map(c => c.id === currentId ? { ...c, ...formData, status: formData.status as 'Active' | 'Trial' } : c));
      showToast("Company updated successfully", "success");
    } else {
      // Add new
      const newCompany: Company = {
        id: Date.now(),
        name: formData.name,
        contactPerson: formData.contactPerson,
        email: formData.email,
        status: formData.status as 'Active' | 'Trial'
      };
      setCompanies(prev => [newCompany, ...prev]);
      showToast("Company added successfully", "success");
    }
    setIsModalOpen(false);
    resetForm();
  };

  const handleDelete = () => {
    if (currentId) {
      setCompanies(prev => prev.filter(c => c.id !== currentId));
      showToast("Company deleted", "info");
      setIsDeleteModalOpen(false);
      setCurrentId(null);
    }
  };

  // -- Render Helpers --

  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.contactPerson.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
            <Building2 className="text-blue-500" /> Companies
          </h1>
          <p className="text-slate-400 mt-1">Manage your client list and track status.</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors shadow-lg shadow-blue-500/20 active:scale-95"
        >
          <Plus size={18} />
          Add New Company
        </button>
      </div>

      {/* Main Content */}
      <Card noPadding className="overflow-hidden min-h-[400px] flex flex-col border border-slate-800 shadow-xl">
        {/* Search Bar */}
        <div className="p-4 border-b border-slate-800 bg-slate-900/50 flex items-center gap-3">
          <Search size={18} className="text-slate-500" />
          <input 
            type="text" 
            placeholder="Search by company or contact..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="bg-transparent border-none focus:outline-none text-sm text-slate-200 placeholder-slate-500 w-full"
          />
        </div>

        {/* Table or Empty State */}
        {companies.length === 0 ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-500 p-12">
            <div className="w-16 h-16 bg-slate-800/50 rounded-full flex items-center justify-center mb-4 ring-1 ring-slate-700">
               <Building2 size={32} className="text-slate-600" />
            </div>
            <h3 className="text-lg font-medium text-slate-300">No companies added yet</h3>
            <p className="max-w-xs mt-2 text-sm text-center mb-6 text-slate-500">Start building your client database to track proposals and deal health.</p>
            <button 
              onClick={openAddModal}
              className="text-blue-400 hover:text-blue-300 font-medium text-sm flex items-center gap-1 transition-colors"
            >
              Add your first company <span aria-hidden="true">&rarr;</span>
            </button>
          </div>
        ) : filteredCompanies.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse min-w-[800px]">
              <thead>
                <tr className="border-b border-slate-800 bg-slate-900/50 text-xs font-semibold text-slate-500 uppercase tracking-wider">
                  <th className="px-6 py-4">Company Name</th>
                  <th className="px-6 py-4">Contact Person</th>
                  <th className="px-6 py-4">Email</th>
                  <th className="px-6 py-4">Status</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-800">
                {filteredCompanies.map((company) => (
                  <tr key={company.id} className="group hover:bg-slate-800/40 transition-colors">
                    <td className="px-6 py-4 text-slate-200 font-medium">
                      {company.name}
                    </td>
                    <td className="px-6 py-4 text-slate-400">
                      <div className="flex items-center gap-2">
                        <User size={14} className="text-slate-600" /> {company.contactPerson}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-400">
                      <div className="flex items-center gap-2">
                        <Mail size={14} className="text-slate-600" /> {company.email}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-medium border ${
                        company.status === 'Active' 
                          ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' 
                          : 'bg-amber-500/10 text-amber-400 border-amber-500/20'
                      }`}>
                        {company.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2 md:opacity-0 md:group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => openEditModal(company)}
                          className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-blue-400 transition-colors"
                          title="Edit"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => openDeleteModal(company.id)}
                          className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-rose-400 transition-colors"
                          title="Delete"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
           <div className="p-12 text-center text-slate-500">
             <Search size={32} className="mx-auto mb-4 opacity-20" />
             <p>No companies found matching "{searchTerm}"</p>
           </div>
        )}
      </Card>

      {/* Add/Edit Modal */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={isEditing ? "Edit Company" : "Add New Company"}
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs font-semibold text-slate-400 mb-1.5 uppercase tracking-wide">Company Name</label>
            <input 
              type="text"
              value={formData.name}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 placeholder-slate-600 transition-all"
              placeholder="e.g. Acme Security"
            />
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-400 mb-1.5 uppercase tracking-wide">Contact Person</label>
            <input 
              type="text"
              value={formData.contactPerson}
              onChange={(e) => setFormData({...formData, contactPerson: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 placeholder-slate-600 transition-all"
              placeholder="e.g. John Doe"
            />
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-400 mb-1.5 uppercase tracking-wide">Email Address</label>
            <input 
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 placeholder-slate-600 transition-all"
              placeholder="john@example.com"
            />
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-400 mb-1.5 uppercase tracking-wide">Status</label>
            <div className="relative">
              <select
                value={formData.status}
                onChange={(e) => setFormData({...formData, status: e.target.value})}
                className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 appearance-none transition-all"
              >
                <option value="Active">Active</option>
                <option value="Trial">Trial</option>
              </select>
              <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-slate-400">
                <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
              </div>
            </div>
          </div>
          <div className="pt-6 flex gap-3">
             <button 
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 py-3 rounded-lg font-medium transition-colors border border-slate-700"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex-1 bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-lg font-medium transition-colors shadow-lg shadow-blue-500/20"
            >
              {isEditing ? "Save Changes" : "Create Company"}
            </button>
          </div>
        </form>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        title="Delete Company"
      >
        <div className="text-center pt-2">
          <div className="w-14 h-14 bg-rose-500/10 rounded-full flex items-center justify-center mx-auto mb-5 ring-1 ring-rose-500/20">
             <AlertTriangle className="text-rose-500" size={28} />
          </div>
          <h4 className="text-lg font-semibold text-white mb-2">Are you sure?</h4>
          <p className="text-slate-400 mb-8 leading-relaxed text-sm">
            You are about to delete this company. This action cannot be undone and will remove all associated proposals and health checks.
          </p>
          <div className="flex gap-3">
             <button 
              onClick={() => setIsDeleteModalOpen(false)}
              className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 py-3 rounded-lg font-medium transition-colors border border-slate-700"
            >
              No, Keep It
            </button>
            <button 
              onClick={handleDelete}
              className="flex-1 bg-rose-600 hover:bg-rose-500 text-white py-3 rounded-lg font-medium transition-colors shadow-lg shadow-rose-500/20"
            >
              Yes, Delete It
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './pages/Dashboard';
import { DiscoveryCopilot } from './pages/DiscoveryCopilot';
import { ProposalReview } from './pages/ProposalReview';
import { DealHealthChecker } from './pages/DealHealthChecker';
import { Companies } from './pages/Companies';
import { PageView } from './types';
import { ToastProvider } from './context/ToastContext';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>(PageView.DASHBOARD);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const handleNavigate = (page: PageView) => {
    setActivePage(page);
    setIsSidebarOpen(false);
  };

  const renderContent = () => {
    switch (activePage) {
      case PageView.DASHBOARD:
        return <Dashboard onNavigate={handleNavigate} />;
      case PageView.DISCOVERY:
        return <DiscoveryCopilot />;
      case PageView.PROPOSAL:
        return <ProposalReview />;
      case PageView.DEAL_HEALTH:
        return <DealHealthChecker />;
      case PageView.COMPANIES:
        return <Companies />;
      case PageView.SETTINGS:
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
            <h2 className="text-xl font-semibold mb-2">Settings</h2>
            <p>User preferences and API configurations would go here.</p>
          </div>
        );
      default:
        return <Dashboard onNavigate={handleNavigate} />;
    }
  };

  return (
    <ToastProvider>
      <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
        {/* Mobile sidebar overlay */}
        {isSidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden"
            onClick={() => setIsSidebarOpen(false)}
          />
        )}

        <Sidebar 
          activePage={activePage} 
          onNavigate={handleNavigate}
          isOpen={isSidebarOpen}
        />

        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <Header 
            activePage={activePage} 
            onMenuClick={() => setIsSidebarOpen(true)}
          />

          <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-smooth">
            <div className="max-w-7xl mx-auto w-full">
              {renderContent()}
            </div>
          </main>
        </div>
      </div>
    </ToastProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { Bell, Search, HelpCircle, Menu } from 'lucide-react';
import { PageView } from '../types';
import { useToast } from '../context/ToastContext';

interface HeaderProps {
  activePage: PageView;
  onMenuClick?: () => void;
}

export const Header: React.FC<HeaderProps> = ({ activePage, onMenuClick }) => {
  const { showToast } = useToast();
  const [searchValue, setSearchValue] = useState('');

  const getPageTitle = (page: PageView) => {
    switch (page) {
      case PageView.DASHBOARD: return 'Dashboard';
      case PageView.DISCOVERY: return 'Discovery Copilot';
      case PageView.PROPOSAL: return 'Proposal Review';
      case PageView.DEAL_HEALTH: return 'Deal Health Checker';
      case PageView.COMPANIES: return 'Companies';
      case PageView.SETTINGS: return 'Settings';
      default: return '';
    }
  };

  const handleSearch = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && searchValue.trim()) {
      showToast(`Searching for "${searchValue}"...`, "info");
      setSearchValue('');
    }
  };

  return (
    <header className="h-16 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md flex items-center justify-between px-4 md:px-6 sticky top-0 z-30">
      <div className="flex items-center gap-4">
        <button 
          onClick={onMenuClick}
          className="md:hidden text-slate-400 hover:text-slate-200 p-1 hover:bg-slate-800 rounded-lg transition-colors"
        >
          <Menu size={24} />
        </button>
        <h2 className="text-lg font-semibold text-slate-100 tracking-tight">{getPageTitle(activePage)}</h2>
      </div>

      <div className="flex items-center gap-3 md:gap-4">
        <div className="relative hidden md:block group">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-500 transition-colors" size={16} />
          <input 
            type="text" 
            placeholder="Search deals..." 
            value={searchValue}
            onChange={(e) => setSearchValue(e.target.value)}
            onKeyDown={handleSearch}
            className="bg-slate-800/50 border border-slate-700 text-sm rounded-lg pl-9 pr-4 py-1.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 w-64 placeholder-slate-500 transition-all"
          />
        </div>

        <button 
          onClick={() => showToast("You have 3 unread notifications", "info")}
          className="text-slate-400 hover:text-slate-200 transition-colors relative p-2 hover:bg-slate-800 rounded-full"
        >
          <Bell size={20} />
          <span className="absolute top-2 right-2 w-2 h-2 bg-rose-500 rounded-full border-2 border-slate-900"></span>
        </button>

        <button 
          onClick={() => showToast("Help center opened", "info")}
          className="text-slate-400 hover:text-slate-200 transition-colors p-2 hover:bg-slate-800 rounded-full"
        >
          <HelpCircle size={20} />
        </button>
      </div>
    </header>
  );
};

import React, { useState } from 'react';
import { Card } from '../components/Card';
import { Tooltip } from '../components/Tooltip';
import { Activity, ShieldAlert, ArrowRight, Zap, RefreshCw } from 'lucide-react';
import { useToast } from '../context/ToastContext';

export const DealHealthChecker: React.FC = () => {
  const { showToast } = useToast();
  const [formData, setFormData] = useState({
    propertyType: 'Residential',
    decisionMakerIdentified: 'Yes',
    daysSinceInteraction: '3',
    proposalSent: 'Yes',
    objections: '',
    urgency: 'Medium',
    competitors: 'Yes'
  });

  const [result, setResult] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    // Reset result if user changes input to encourage re-evaluation
    if (result) setResult(null); 
  };

  const handleReset = () => {
    setFormData({
        propertyType: 'Residential',
        decisionMakerIdentified: 'Yes',
        daysSinceInteraction: '',
        proposalSent: 'Yes',
        objections: '',
        urgency: 'Medium',
        competitors: 'No'
    });
    setResult(null);
    showToast("Form reset", "info");
  };

  const calculateHealth = () => {
    setIsAnalyzing(true);
    setResult(null);

    // Realistic delay for analysis feeling
    setTimeout(() => {
      const objectionsExist = formData.objections.trim().length > 0;
      const days = parseInt(formData.daysSinceInteraction || '0');

      let status = 'Strong';
      let probability = 75;
      let reasoning = '';
      let nextActions = [];

      // LOGIC IMPLEMENTATION

      // 1. Likely Lost Condition: No DM and Ghosted > 7 Days
      if (formData.decisionMakerIdentified === 'No' && days > 7) {
        status = 'Likely Lost';
        probability = 15;
        reasoning = 'Critically low engagement. Lacking a decision maker combined with over a week of silence indicates the prospect has likely moved on or deprioritized this.';
        nextActions = [
           'Send a "break-up" email (e.g., "Should I close this file?") to trigger a response.',
           'Call the main office line to identify the correct stakeholder.',
           'Do not invest more time in proposal customization until contact is re-established.'
        ];
      } 
      // 2. At Risk Condition: Objections AND Competitors
      else if (objectionsExist && formData.competitors === 'Yes') {
        status = 'At Risk';
        probability = 40;
        reasoning = `The deal is precarious. The client has voiced concerns ("${formData.objections.substring(0, 30)}...") and is actively shopping competitors. They are looking for a reason to say no.`;
        nextActions = [
           'Schedule a "barrier removal" call specifically to address the objection.',
           'Prepare a competitor comparison sheet highlighting your unique strengths.',
           'Offer a limited-time incentive for signing this week.'
        ];
      }
      // 3. Strong Condition: High Urgency + DM Identified
      else if (formData.urgency === 'High' && formData.decisionMakerIdentified === 'Yes') {
        status = 'Strong';
        probability = 85;
        reasoning = 'Excellent momentum. High urgency from the client combined with direct access to the decision maker is the perfect recipe for a close.';
        nextActions = [
           'Send the contract immediately via Docusign.',
           'Propose a tentative start date to assume the sale.',
           'Ask: "Is there anything preventing you from signing today?"'
        ];
      }
      // 4. Moderate/Default
      else {
        status = 'Moderate';
        probability = 60;
        reasoning = 'The deal is stable but lacks urgency. You have some engagement, but no clear buying signal has been triggered yet.';
        nextActions = [
           'Send a relevant case study for a ' + formData.propertyType + ' property.',
           'Propose a site walkthrough if not already completed.',
           'Check in via text message for a quicker response.'
        ];
      }

      setResult({
        status,
        probability,
        reasoning,
        nextActions
      });
      setIsAnalyzing(false);
      showToast("Deal analysis complete", "success");
    }, 800);
  };

  return (
    <div className="space-y-6 animate-fade-in">
       <div className="mb-8">
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-3">
            <Activity className="text-rose-500" /> Deal Health Checker
          </h1>
          <p className="text-slate-400 mt-2 text-sm max-w-2xl leading-relaxed">
            Evaluate deal risk and get clear next actions based on prospect behavior and engagement metrics.
          </p>
        </div>

        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">

          {/* Form Section */}
          <div className="xl:col-span-7">
            <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm">
              <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-800/50">
                 <h3 className="text-lg font-semibold text-slate-100">Deal Parameters</h3>
                 <button 
                    onClick={handleReset}
                    className="text-xs font-medium text-blue-400 hover:text-blue-300 transition-colors flex items-center gap-1.5 px-3 py-1.5 hover:bg-slate-800 rounded-lg"
                 >
                    <RefreshCw size={12} /> Reset Form
                 </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-6">
                 <div>
                    <label className="label-text">
                      Property Type
                      <Tooltip text="The primary category of the facility requiring security services." />
                    </label>
                    <div className="relative">
                      <select 
                        className="input-field appearance-none"
                        value={formData.propertyType}
                        onChange={(e) => handleChange('propertyType', e.target.value)}
                      >
                         <option>Residential</option>
                         <option>Commercial</option>
                         <option>Industrial</option>
                         <option>Retail</option>
                         <option>Event</option>
                      </select>
                      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-400">
                        <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                      </div>
                    </div>
                 </div>

                 <div>
                    <label className="label-text">
                      Decision Maker Identified?
                      <Tooltip text="Have you confirmed exactly who has the final authority to sign the contract?" />
                    </label>
                    <div className="relative">
                      <select 
                        className="input-field appearance-none"
                        value={formData.decisionMakerIdentified}
                        onChange={(e) => handleChange('decisionMakerIdentified', e.target.value)}
                      >
                         <option>Yes</option>
                         <option>No</option>
                         <option>Unsure</option>
                      </select>
                      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-400">
                        <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                      </div>
                    </div>
                 </div>

                 <div>
                    <label className="label-text">
                      Last Interaction (Days ago)
                      <Tooltip text="Number of days since the last two-way communication (email, call, or meeting)." />
                    </label>
                    <input 
                      type="number" 
                      min="0"
                      className="input-field"
                      placeholder="e.g. 3"
                      value={formData.daysSinceInteraction}
                      onChange={(e) => handleChange('daysSinceInteraction', e.target.value)}
                    />
                 </div>

                 <div>
                    <label className="label-text">
                      Proposal Sent?
                      <Tooltip text="Has the formal pricing and scope of work document been delivered?" />
                    </label>
                    <div className="relative">
                      <select 
                        className="input-field appearance-none"
                        value={formData.proposalSent}
                        onChange={(e) => handleChange('proposalSent', e.target.value)}
                      >
                         <option>Yes</option>
                         <option>No</option>
                         <option>Drafting</option>
                      </select>
                      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-400">
                        <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                      </div>
                    </div>
                 </div>

                 <div>
                    <label className="label-text">
                      Client Urgency
                      <Tooltip text="How quickly does the client need to deploy services on-site?" />
                    </label>
                    <div className="relative">
                      <select 
                        className="input-field appearance-none"
                        value={formData.urgency}
                        onChange={(e) => handleChange('urgency', e.target.value)}
                      >
                         <option>High</option>
                         <option>Medium</option>
                         <option>Low</option>
                      </select>
                      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-400">
                        <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                      </div>
                    </div>
                 </div>

                 <div>
                    <label className="label-text">
                      Competitors Involved?
                      <Tooltip text="Are other security guard companies actively bidding on this contract?" />
                    </label>
                    <div className="relative">
                      <select 
                        className="input-field appearance-none"
                        value={formData.competitors}
                        onChange={(e) => handleChange('competitors', e.target.value)}
                      >
                         <option>Yes</option>
                         <option>No</option>
                         <option>Unknown</option>
                      </select>
                      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-400">
                        <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                      </div>
                    </div>
                 </div>

                 <div className="md:col-span-2">
                    <label className="label-text">
                      Objections Raised (Optional)
                      <Tooltip text="Any specific concerns mentioned by the client (e.g., price, reputation, timing)." />
                    </label>
                    <input 
                      type="text" 
                      className="input-field"
                      placeholder="e.g. Price too high, current contract not expired..."
                      value={formData.objections}
                      onChange={(e) => handleChange('objections', e.target.value)}
                    />
                 </div>
              </div>

              <div className="mt-8 pt-6 border-t border-slate-800">
                <button 
                  onClick={calculateHealth}
                  disabled={isAnalyzing}
                  className="w-full bg-slate-100 hover:bg-white text-slate-900 font-bold py-4 rounded-lg shadow-lg shadow-white/5 transition-all active:scale-[0.99] disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2.5 text-sm uppercase tracking-wide"
                >
                  {isAnalyzing ? (
                     <>
                        <div className="w-5 h-5 border-2 border-slate-900/30 border-t-slate-900 rounded-full animate-spin"></div>
                        Evaluating...
                     </>
                  ) : (
                     <>
                        <Zap size={18} className="fill-current" />
                        Evaluate Deal Health
                     </>
                  )}
                </button>
              </div>
            </div>
          </div>

          {/* Results Section */}
          <div className="xl:col-span-5 h-full">
             {result ? (
               <div className="space-y-4 animate-fade-in h-full flex flex-col">
                  {/* Status Card */}
                  <div className={`rounded-xl p-8 text-center border transition-all duration-500 relative overflow-hidden ${
                    result.status === 'Strong' ? 'bg-slate-900 border-emerald-500/30' : 
                    result.status === 'Moderate' ? 'bg-slate-900 border-blue-500/30' :
                    result.status === 'At Risk' ? 'bg-slate-900 border-amber-500/30' : 
                    'bg-slate-900 border-rose-500/30'
                  }`}>
                     <div className={`absolute inset-0 opacity-5 bg-gradient-to-br ${
                         result.status === 'Strong' ? 'from-emerald-500 to-transparent' : 
                         result.status === 'Moderate' ? 'from-blue-500 to-transparent' :
                         result.status === 'At Risk' ? 'from-amber-500 to-transparent' : 
                         'from-rose-500 to-transparent'
                     }`}></div>

                     <h2 className={`text-4xl font-bold mb-3 tracking-tight ${
                       result.status === 'Strong' ? 'text-emerald-400' : 
                       result.status === 'Moderate' ? 'text-blue-400' :
                       result.status === 'At Risk' ? 'text-amber-400' : 
                       'text-rose-400'
                     }`}>{result.status}</h2>
                     <p className="text-slate-400 text-xs uppercase tracking-[0.2em] font-bold mb-8">Deal Status</p>

                     <div className="relative inline-flex items-center justify-center">
                        <svg className="w-32 h-32 transform -rotate-90">
                           <circle className="text-slate-800" strokeWidth="8" stroke="currentColor" fill="transparent" r="56" cx="64" cy="64" />
                           <circle 
                              className={`${
                                 result.status === 'Strong' ? 'text-emerald-500' : 
                                 result.status === 'Moderate' ? 'text-blue-500' :
                                 result.status === 'At Risk' ? 'text-amber-500' : 
                                 'text-rose-500'
                              } transition-all duration-1000 ease-out`} 
                              strokeWidth="8" 
                              strokeDasharray={351.8}
